// Extracts each LLM's answer and confidence from raw output, validates the JSON structure, and flags invalid responses.

const allItems = $input.all();
const parsedResponses = [];

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];

  let modelName = `Model ${i + 1}`;

  try {
    const rawNodeName = item.json?.$node?.name || "";
    const cleanedNodeName = rawNodeName
      .replace(/^LLM \d+ - /, "")
      .replace(/\d+$/, "")
      .trim();

    if (cleanedNodeName.length >= 3) {
      modelName = cleanedNodeName;
    }
  } catch (nameError) {
    modelName = `Model ${i + 1}`;
  }

  try {
    const rawOutput = item.json.output || item.json.text || "";
    let cleanedOutput = rawOutput.trim();

    if (cleanedOutput.startsWith("```json")) cleanedOutput = cleanedOutput.slice(7);
    if (cleanedOutput.startsWith("```")) cleanedOutput = cleanedOutput.slice(3);
    if (cleanedOutput.endsWith("```")) cleanedOutput = cleanedOutput.slice(0, -3);
    cleanedOutput = cleanedOutput.trim();

    const parsedJson = JSON.parse(cleanedOutput);

    const hasValidAnswer = parsedJson.answer && typeof parsedJson.answer === "string";
    const hasValidConfidence = typeof parsedJson.confidence === "number";

    if (!hasValidAnswer || !hasValidConfidence) {
      throw new Error("Invalid response structure: missing answer or confidence");
    }

    const clampedConfidence = Math.max(0, Math.min(1, parsedJson.confidence));

    parsedResponses.push({
      model: modelName,
      answer: parsedJson.answer.trim(),
      originalConfidence: clampedConfidence,
      reasoning: parsedJson.reasoning || "",
      valid: true,
    });
  } catch (parseError) {
    parsedResponses.push({
      model: modelName,
      answer: "Parse error",
      originalConfidence: 0.0,
      reasoning: parseError.message,
      valid: false,
    });
  }
}

const validResponseCount = parsedResponses.filter((r) => r.valid).length;

return {
  json: {
    responses: parsedResponses,
    validCount: validResponseCount,
  },
};

// Compares every valid LLM response using both Jaccard and Cosine similarity for accurate agreement detection, then attaches an average similarity score to each.

const allResponses = $input.first().json.responses;
const validResponses = allResponses.filter((r) => r.valid);

if (validResponses.length < 2) {
  return {
    json: {
      responses: validResponses,
      similarityMatrix: [],
      error: "Not enough valid responses to compare",
    },
  };
}

function normalizeAnswer(text) {
  return text
    .toLowerCase()
    .replace(/[.,!?;:'"()\-]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function getWordFrequency(text) {
  const words = text.split(/\s+/);
  const frequency = {};

  for (const word of words) {
    frequency[word] = (frequency[word] || 0) + 1;
  }

  return frequency;
}

function getJaccardSimilarity(textA, textB) {
  const wordsA = new Set(textA.split(/\s+/));
  const wordsB = new Set(textB.split(/\s+/));

  const sharedWords = new Set([...wordsA].filter((word) => wordsB.has(word)));
  const allWords = new Set([...wordsA, ...wordsB]);

  return sharedWords.size / allWords.size;
}

function getCosineSimilarity(textA, textB) {
  const frequencyA = getWordFrequency(textA);
  const frequencyB = getWordFrequency(textB);

  const allUniqueWords = new Set([
    ...Object.keys(frequencyA),
    ...Object.keys(frequencyB),
  ]);

  let dotProduct = 0;
  let magnitudeA = 0;
  let magnitudeB = 0;

  for (const word of allUniqueWords) {
    const countA = frequencyA[word] || 0;
    const countB = frequencyB[word] || 0;

    dotProduct += countA * countB;
    magnitudeA += countA * countA;
    magnitudeB += countB * countB;
  }

  const magnitude = Math.sqrt(magnitudeA) * Math.sqrt(magnitudeB);

  if (magnitude === 0) return 0;

  return dotProduct / magnitude;
}

function getCombinedSimilarity(textA, textB) {
  const normalizedA = normalizeAnswer(textA);
  const normalizedB = normalizeAnswer(textB);

  const shorter = normalizedA.length <= normalizedB.length ? normalizedA : normalizedB;
  const longer = normalizedA.length > normalizedB.length ? normalizedA : normalizedB;

  if (shorter.length > 0 && longer.includes(shorter)) {
    return 0.95;
  }

  const firstSentenceA = normalizedA.split(/[.!?]/)[0].trim();
  const firstSentenceB = normalizedB.split(/[.!?]/)[0].trim();

  const firstSentenceSimilarity = getCosineSimilarity(firstSentenceA, firstSentenceB);

  const jaccardScore = getJaccardSimilarity(normalizedA, normalizedB);
  const cosineScore = getCosineSimilarity(normalizedA, normalizedB);

  const JACCARD_WEIGHT = 0.25;
  const COSINE_WEIGHT = 0.45;
  const FIRST_SENTENCE_WEIGHT = 0.30;

  return (jaccardScore * JACCARD_WEIGHT) + (cosineScore * COSINE_WEIGHT) + (firstSentenceSimilarity * FIRST_SENTENCE_WEIGHT);
}

const similarityMatrix = [];

for (let i = 0; i < validResponses.length; i++) {
  const rowScores = [];

  for (let j = 0; j < validResponses.length; j++) {
    if (i === j) {
      rowScores.push(1.0);
    } else {
      const score = getCombinedSimilarity(
        validResponses[i].answer,
        validResponses[j].answer
      );
      rowScores.push(score);
    }
  }

  similarityMatrix.push(rowScores);
}

const averageSimilarityPerResponse = similarityMatrix.map((row) => {
  const totalExcludingSelf = row.reduce((sum, value) => sum + value, 0) - 1;
  const otherResponseCount = row.length - 1;
  return totalExcludingSelf / otherResponseCount;
});

const responsesWithSimilarity = validResponses.map((response, index) => ({
  ...response,
  avgSimilarityToOthers: averageSimilarityPerResponse[index],
}));

return {
  json: {
    responses: responsesWithSimilarity,
    similarityMatrix: similarityMatrix,
  },
};

// Adjusts each model's confidence based on agreement patterns: penalizes overconfident outliers, boosts underconfident consensus matches, and moderately reduces mid-confidence outliers.

const responses = $input.first().json.responses;

const HIGH_CONFIDENCE_THRESHOLD = 0.80;
const LOW_AGREEMENT_THRESHOLD = 0.30;
const STRONG_AGREEMENT_THRESHOLD = 0.50;
const MODERATE_DISAGREEMENT_THRESHOLD = 0.30;
const PENALTY_MULTIPLIER = 0.70;

const calibratedResponses = responses.map((response) => {
  let adjustedConfidence = response.originalConfidence;
  let adjustmentReason = "No calibration needed";
  let wasCalibrated = false;

  const isHighConfidence = response.originalConfidence >= HIGH_CONFIDENCE_THRESHOLD;
  const isLowAgreement = response.avgSimilarityToOthers < LOW_AGREEMENT_THRESHOLD;
  const isLowConfidence = response.originalConfidence < 0.50;
  const isStrongAgreement = response.avgSimilarityToOthers >= STRONG_AGREEMENT_THRESHOLD;
  const isMidConfidence = response.originalConfidence >= 0.60;
  const isModerateDisagreement = response.avgSimilarityToOthers < MODERATE_DISAGREEMENT_THRESHOLD;

  if (isHighConfidence && isLowAgreement) {
    adjustedConfidence = Math.min(response.originalConfidence, 0.40);
    adjustmentReason = "Overconfident outlier: High self-reported confidence but low agreement with other models. Likely hallucination, confidence reduced.";
    wasCalibrated = true;
  } else if (isLowConfidence && isStrongAgreement) {
    adjustedConfidence = Math.max(response.originalConfidence, 0.65);
    adjustmentReason = "Consensus boost: Low self-confidence but strong agreement with other models. Confidence increased.";
    wasCalibrated = true;
  } else if (isMidConfidence && isModerateDisagreement) {
    adjustedConfidence = response.originalConfidence * PENALTY_MULTIPLIER;
    adjustmentReason = "Moderate outlier: Disagreement with consensus detected. Confidence reduced moderately.";
    wasCalibrated = true;
  }

  return {
    ...response,
    calibratedConfidence: Math.round(adjustedConfidence * 100) / 100,
    calibrated: wasCalibrated,
    calibrationReason: adjustmentReason,
  };
});

const totalSimilarity = responses.reduce((sum, r) => sum + r.avgSimilarityToOthers, 0);
const averageSimilarity = totalSimilarity / responses.length;
const hasStrongConsensus = averageSimilarity >= STRONG_AGREEMENT_THRESHOLD;
const hasExtremeDivergence = averageSimilarity < 0.10;

return {
  json: {
    responses: calibratedResponses,
    consensusMetrics: {
      avgSimilarity: Math.round(averageSimilarity * 100) / 100,
      hasStrongConsensus: hasStrongConsensus,
      hasExtremeDivergence: hasExtremeDivergence,
    },
  },
};

// Ranks all responses by calibrated confidence weight and picks the top answer as primary consensus, collecting minority views above 15% weight.

const responses = $input.first().json.responses;
const consensusMetrics = $input.first().json.consensusMetrics;

const totalCalibratedConfidence = responses.reduce((sum, r) => sum + r.calibratedConfidence, 0);

const responsesWithWeights = responses.map((response) => ({
  ...response,
  weight: totalCalibratedConfidence > 0
    ? response.calibratedConfidence / totalCalibratedConfidence
    : 1 / responses.length,
}));

responsesWithWeights.sort((a, b) => b.weight - a.weight);

const topWeightedResponse = responsesWithWeights[0];
const remainingResponses = responsesWithWeights.slice(1);
const significantMinorityViews = remainingResponses.filter((r) => r.weight > 0.15);

const calibratedModelCount = responsesWithWeights.filter((r) => r.calibrated).length;

const consensusSummary = {
  primaryAnswer: topWeightedResponse.answer,
  primaryWeight: Math.round(topWeightedResponse.weight * 100),
  primaryModel: topWeightedResponse.model,
  consensusStrength: consensusMetrics.avgSimilarity,
  calibrationsApplied: calibratedModelCount,
  minorityViews: significantMinorityViews.map((r) => ({
    answer: r.answer,
    weight: Math.round(r.weight * 100),
    model: r.model,
  })),
};

return {
  json: {
    consensusSummary: consensusSummary,
    allResponses: responsesWithWeights,
    mode: "weighted_consensus",
  },
};

// When models disagree too much for weighted consensus, sorts all responses by original confidence and returns them as individual perspectives for the user to review.

const responses = $input.first().json.responses;

const sortedByOriginalConfidence = [...responses].sort(
  (a, b) => b.originalConfidence - a.originalConfidence
);

const formattedPerspectives = sortedByOriginalConfidence.map((response) => ({
  model: response.model,
  answer: response.answer,
  confidence: response.originalConfidence,
  similarityToOthers: response.avgSimilarityToOthers,
}));

return {
  json: {
    peerReviewSummary: {
      status: "extreme_divergence_detected",
      explanation: "Models disagree significantly. Showing all perspectives instead of weighted consensus.",
      responses: formattedPerspectives,
    },
    mode: "peer_review_fallback",
  },
};

// Formats the final JSON result into a readable chat message with tiered agreement display, calibration notes, and per-model breakdowns.

const inputData = $input.first().json;
const consensusMode = inputData.mode;

let chatMessage = "";

if (consensusMode === "weighted_consensus") {
  const answer = inputData.result.answer;
  const agreementLevel = inputData.result.consensusStrength;

  const agreementPercent = parseInt(agreementLevel);
  const filledBlocks = Math.floor(agreementPercent / 10);
  const emptyBlocks = 10 - filledBlocks;
  const agreementBar = "█".repeat(filledBlocks) + "░".repeat(emptyBlocks);

  let agreementLabel = "";

  if (agreementPercent >= 70) {
    agreementLabel = "✅ **Strong consensus across all models**";
  } else if (agreementPercent >= 40) {
    agreementLabel = "🟡 **Models mostly agree, with some variation in detail**";
  } else {
    agreementLabel = "🟠 **Models loosely agree, but answers vary significantly**";
  }

  chatMessage = `${agreementLabel}\n\n${answer}\n\n`;
  chatMessage += `**Agreement level:** ${agreementBar} ${agreementLevel}\n`;

  const calibrationCount = inputData.calibrationReport?.calibrationsApplied || 0;

  if (calibrationCount > 0) {
    const plural = calibrationCount > 1 ? "s" : "";
    chatMessage += `\n⚙️ I adjusted ${calibrationCount} model${plural} that seemed overconfident\n`;
  }

  const minorityOpinions = inputData.minorityOpinions || [];

  if (minorityOpinions.length > 0) {
    chatMessage += `\n**💭 Other perspectives:**\n`;

    for (const opinion of minorityOpinions) {
      const maxAnswerLength = 150;
      const truncatedAnswer = opinion.answer.length > maxAnswerLength
        ? opinion.answer.substring(0, maxAnswerLength) + "..."
        : opinion.answer;
      chatMessage += `• ${truncatedAnswer}\n`;
    }
  }
} else {
  chatMessage = `⚠️ **The models don't agree on this one**\n\n`;
  chatMessage += `This usually means the question is:\n`;
  chatMessage += `• Controversial or debatable\n`;
  chatMessage += `• Ambiguous (could mean different things)\n`;
  chatMessage += `• Based on outdated information\n\n`;
  chatMessage += `Here's what each model thinks:\n\n`;

  const allPerspectives = inputData.allPerspectives || [];

  for (let i = 0; i < allPerspectives.length; i++) {
    const perspective = allPerspectives[i];
    const confidencePercent = Math.round(perspective.confidence * 100);

    let confidenceEmoji = "🤷";
    if (confidencePercent >= 90) confidenceEmoji = "💪";
    else if (confidencePercent >= 70) confidenceEmoji = "👍";
    else if (confidencePercent >= 50) confidenceEmoji = "🤔";

    chatMessage += `${confidenceEmoji} **Model ${i + 1}** (${confidencePercent}% sure)\n`;
    chatMessage += `${perspective.answer}\n\n`;
  }

  chatMessage += `---\n💡 **My recommendation:** Review all perspectives above and use your judgment.`;
}

const failedModels = inputData.failedModels || [];

if (failedModels.length > 0) {
  const failedNames = failedModels.join(", ");
  const plural = failedModels.length > 1 ? "s" : "";
  chatMessage += `\n\n⚠️ **Note:** ${failedNames} model${plural} failed to respond and was excluded from the analysis.`;
}

return {
  json: {
    chatResponse: chatMessage,
  },
};

// Builds the structured output object with result summary, calibration report, and full model breakdown depending on whether consensus or peer review mode was used.

const inputData = $input.first().json;
const consensusMode = inputData.mode;

let finalOutput = {
  mode: consensusMode,
  timestamp: new Date().toISOString(),
};

if (consensusMode === "weighted_consensus") {
  const summary = inputData.consensusSummary;
  const allModelResponses = inputData.allResponses;

  finalOutput.result = {
    answer: summary.primaryAnswer,
    confidence: `${summary.primaryWeight}% (weighted)`,
    consensusStrength: `${Math.round(summary.consensusStrength * 100)}%`,
    source: `${summary.primaryModel} (${summary.primaryWeight}% weight)`,
  };

  finalOutput.minorityOpinions = summary.minorityViews;

  const calibratedModels = allModelResponses.filter((r) => r.calibrated);

  finalOutput.calibrationReport = {
    calibrationsApplied: summary.calibrationsApplied,
    details: calibratedModels.map((r) => ({
      model: r.model,
      originalConfidence: `${Math.round(r.originalConfidence * 100)}%`,
      calibratedConfidence: `${Math.round(r.calibratedConfidence * 100)}%`,
      reason: r.calibrationReason,
    })),
  };

  finalOutput.fullBreakdown = allModelResponses.map((r) => ({
    model: r.model,
    answer: r.answer,
    originalConfidence: `${Math.round(r.originalConfidence * 100)}%`,
    calibratedConfidence: `${Math.round(r.calibratedConfidence * 100)}%`,
    weight: `${Math.round(r.weight * 100)}%`,
    similarityToOthers: `${Math.round(r.avgSimilarityToOthers * 100)}%`,
    wasCalibrated: r.calibrated,
  }));
} else {
  finalOutput.result = {
    answer: "Multiple conflicting perspectives - see all responses below",
    confidence: "N/A (extreme divergence)",
    consensusStrength: "< 25%",
    source: "Peer review fallback mode",
  };

  finalOutput.allPerspectives = inputData.peerReviewSummary.responses;
  finalOutput.explanation = inputData.peerReviewSummary.explanation;
}

finalOutput.failedModels = (inputData.allResponses || [])
  .filter((r) => r.originalConfidence === 0 && r.answer === "Parse error")
  .map((r) => r.model);

return { json: finalOutput };
